import React, { useState } from "react";

function CompareModels() {
  const [results, setResults] = useState(null);

  const runCompare = async () => {
    const res = await fetch("http://127.0.0.1:5000/compare", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({})
    });

    const data = await res.json();
    console.log("RESULT:", data); // 🔥 debug

    if (data.status === "success") {
      setResults(data.results);
    }
  };

  const renderBlock = (title, m) => {
    if (!m) return <p>{title}: No data</p>;

    return (
      <div style={{ marginTop: "20px", border: "1px solid #ccc", padding: "15px" }}>
        <h3>{title}</h3>

        <p>TPR: {m.TPR}%</p>
        <p>FNR: {m.FNR}%</p>
        <p>FPR: {m.FPR}%</p>
        <p>TNR: {m.TNR}%</p>
        <p>F1 Score: {m.F1}%</p>

        <p>
          Confusion → TN: {m.TN} | FP: {m.FP} | FN: {m.FN} | TP: {m.TP}
        </p>
      </div>
    );
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>📊 OCSVM vs Isolation Forest</h2>

      <button onClick={runCompare}>Run Comparison</button>

      {results && (
        <div>
          {renderBlock("OCSVM", results.ocsvm)}
          {renderBlock("Isolation Forest", results.isolation_forest)}
        </div>
      )}
    </div>
  );
}

export default CompareModels;
